import { ScrollArea as ScrollAreaPrimitive } from '@base-ui/react/scroll-area';
import { forwardRef, type ComponentRef, type ForwardedRef, type ReactNode } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './ScrollArea.module.css';

type FadeDirection = boolean | 'vertical' | 'horizontal' | 'both';
type Scrollbars = 'vertical' | 'horizontal' | 'both' | false;

const ScrollAreaRoot = forwardRef(function ScrollAreaRoot(
  { className, ...props }: ScrollAreaPrimitive.Root.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Root>>,
) {
  return (
    <ScrollAreaPrimitive.Root
      ref={ref}
      data-slot="scroll-area-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

const ScrollAreaViewport = forwardRef(function ScrollAreaViewport(
  { className, ...props }: ScrollAreaPrimitive.Viewport.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Viewport>>,
) {
  return (
    <ScrollAreaPrimitive.Viewport
      ref={ref}
      data-slot="scroll-area-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
});

const ScrollAreaContent = forwardRef(function ScrollAreaContent(
  { className, ...props }: ScrollAreaPrimitive.Content.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Content>>,
) {
  return (
    <ScrollAreaPrimitive.Content
      ref={ref}
      data-slot="scroll-area-content"
      className={mergeClassName(className, styles.content)}
      {...props}
    />
  );
});

const ScrollAreaScrollbar = forwardRef(function ScrollAreaScrollbar(
  { className, ...props }: ScrollAreaPrimitive.Scrollbar.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Scrollbar>>,
) {
  return (
    <ScrollAreaPrimitive.Scrollbar
      ref={ref}
      data-slot="scroll-area-scrollbar"
      className={mergeClassName(className, styles.scrollbar)}
      {...props}
    />
  );
});

const ScrollAreaThumb = forwardRef(function ScrollAreaThumb(
  { className, ...props }: ScrollAreaPrimitive.Thumb.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Thumb>>,
) {
  return (
    <ScrollAreaPrimitive.Thumb
      ref={ref}
      data-slot="scroll-area-thumb"
      className={mergeClassName(className, styles.thumb)}
      {...props}
    />
  );
});

const ScrollAreaCorner = forwardRef(function ScrollAreaCorner(
  { className, ...props }: ScrollAreaPrimitive.Corner.Props,
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Corner>>,
) {
  return (
    <ScrollAreaPrimitive.Corner
      ref={ref}
      data-slot="scroll-area-corner"
      className={mergeClassName(className, styles.corner)}
      {...props}
    />
  );
});

const ScrollArea = forwardRef(function ScrollArea(
  {
    className,
    children,
    fade = false,
    scrollbars = 'vertical',
    ...props
  }: ScrollAreaPrimitive.Root.Props & {
    children?: ReactNode;
    fade?: FadeDirection;
    scrollbars?: Scrollbars;
  },
  ref: ForwardedRef<ComponentRef<typeof ScrollAreaPrimitive.Root>>,
) {
  const fadeDirection = fade === true ? 'vertical' : fade || undefined;
  const hasVerticalScrollbar = scrollbars === 'vertical' || scrollbars === 'both';
  const hasHorizontalScrollbar = scrollbars === 'horizontal' || scrollbars === 'both';

  return (
    <ScrollAreaRoot ref={ref} className={className} {...props} data-fade={fadeDirection}>
      <ScrollAreaViewport>
        <ScrollAreaContent>{children}</ScrollAreaContent>
      </ScrollAreaViewport>
      {hasVerticalScrollbar ? (
        <ScrollAreaScrollbar>
          <ScrollAreaThumb />
        </ScrollAreaScrollbar>
      ) : null}
      {hasHorizontalScrollbar ? (
        <ScrollAreaScrollbar orientation="horizontal">
          <ScrollAreaThumb />
        </ScrollAreaScrollbar>
      ) : null}
      {hasVerticalScrollbar && hasHorizontalScrollbar ? <ScrollAreaCorner /> : null}
    </ScrollAreaRoot>
  );
});

export {
  ScrollArea,
  ScrollAreaRoot,
  ScrollAreaViewport,
  ScrollAreaContent,
  ScrollAreaScrollbar,
  ScrollAreaThumb,
  ScrollAreaCorner,
};

@layer ui.components {
  .root {
    position: relative;
    box-sizing: border-box;
    width: var(--scroll-area-width, 100%);
    height: var(--scroll-area-height, 100%);
    color: var(--scroll-area-color, var(--color-foreground));
  }

  .viewport {
    box-sizing: border-box;
    width: 100%;
    height: 100%;
    border-radius: var(--scroll-area-radius, var(--radius-md));
    background-color: var(--scroll-area-bg, transparent);
    outline: 0;

    .root[data-fade='vertical'] &,
    .root[data-fade='both'] & {
      mask-image: linear-gradient(
        to bottom,
        transparent 0,
        black
          min(
            var(--scroll-area-fade-start-size, var(--scroll-area-fade-size, var(--spacing-10))),
            var(--scroll-area-overflow-y-start, 0px)
          ),
        black
          calc(
            100% -
              min(
                var(--scroll-area-fade-end-size, var(--scroll-area-fade-size, var(--spacing-10))),
                var(--scroll-area-overflow-y-end, 0px)
              )
          ),
        transparent 100%
      );
      mask-repeat: no-repeat;
    }

    .root[data-fade='horizontal'] & {
      mask-image: linear-gradient(
        to right,
        transparent 0,
        black
          min(
            var(
              --scroll-area-fade-inline-start-size,
              var(--scroll-area-fade-size, var(--spacing-10))
            ),
            var(--scroll-area-overflow-x-start, 0px)
          ),
        black
          calc(
            100% -
              min(
                var(
                  --scroll-area-fade-inline-end-size,
                  var(--scroll-area-fade-size, var(--spacing-10))
                ),
                var(--scroll-area-overflow-x-end, 0px)
              )
          ),
        transparent 100%
      );
      mask-repeat: no-repeat;
    }

    .root:dir(rtl)[data-fade='horizontal'] & {
      mask-image: linear-gradient(
        to left,
        transparent 0,
        black
          min(
            var(
              --scroll-area-fade-inline-start-size,
              var(--scroll-area-fade-size, var(--spacing-10))
            ),
            var(--scroll-area-overflow-x-start, 0px)
          ),
        black
          calc(
            100% -
              min(
                var(
                  --scroll-area-fade-inline-end-size,
                  var(--scroll-area-fade-size, var(--spacing-10))
                ),
                var(--scroll-area-overflow-x-end, 0px)
              )
          ),
        transparent 100%
      );
    }

    .root[data-fade='both'] & {
      mask-image:
        linear-gradient(
          to bottom,
          transparent 0,
          black
            min(
              var(--scroll-area-fade-start-size, var(--scroll-area-fade-size, var(--spacing-10))),
              var(--scroll-area-overflow-y-start, 0px)
            ),
          black
            calc(
              100% -
                min(
                  var(--scroll-area-fade-end-size, var(--scroll-area-fade-size, var(--spacing-10))),
                  var(--scroll-area-overflow-y-end, 0px)
                )
            ),
          transparent 100%
        ),
        linear-gradient(
          to right,
          transparent 0,
          black
            min(
              var(
                --scroll-area-fade-inline-start-size,
                var(--scroll-area-fade-size, var(--spacing-10))
              ),
              var(--scroll-area-overflow-x-start, 0px)
            ),
          black
            calc(
              100% -
                min(
                  var(
                    --scroll-area-fade-inline-end-size,
                    var(--scroll-area-fade-size, var(--spacing-10))
                  ),
                  var(--scroll-area-overflow-x-end, 0px)
                )
            ),
          transparent 100%
        );
      mask-composite: intersect;
    }

    .root:dir(rtl)[data-fade='both'] & {
      mask-image:
        linear-gradient(
          to bottom,
          transparent 0,
          black
            min(
              var(--scroll-area-fade-start-size, var(--scroll-area-fade-size, var(--spacing-10))),
              var(--scroll-area-overflow-y-start, 0px)
            ),
          black
            calc(
              100% -
                min(
                  var(--scroll-area-fade-end-size, var(--scroll-area-fade-size, var(--spacing-10))),
                  var(--scroll-area-overflow-y-end, 0px)
                )
            ),
          transparent 100%
        ),
        linear-gradient(
          to left,
          transparent 0,
          black
            min(
              var(
                --scroll-area-fade-inline-start-size,
                var(--scroll-area-fade-size, var(--spacing-10))
              ),
              var(--scroll-area-overflow-x-start, 0px)
            ),
          black
            calc(
              100% -
                min(
                  var(
                    --scroll-area-fade-inline-end-size,
                    var(--scroll-area-fade-size, var(--spacing-10))
                  ),
                  var(--scroll-area-overflow-x-end, 0px)
                )
            ),
          transparent 100%
        );
    }

    &:focus-visible {
      outline: var(--scroll-area-focus-ring-width, var(--border-width-sm)) solid
        var(--scroll-area-focus-ring-color, var(--color-ring));
      outline-offset: var(--scroll-area-focus-ring-offset, -1px);
    }
  }

  .content {
    box-sizing: border-box;
    display: block;
    padding: var(--scroll-area-content-padding, 0);
  }

  .scrollbar {
    --_scroll-area-scrollbar-margin: var(
      --scroll-area-scrollbar-margin,
      calc(var(--spacing-1) / 2)
    );
    --_scroll-area-scrollbar-hit-area-size: var(--scroll-area-scrollbar-hit-area-size, 1.25rem);

    position: absolute;
    box-sizing: border-box;
    display: flex;
    justify-content: center;
    padding: var(--scroll-area-scrollbar-padding, 0);
    border-radius: var(--scroll-area-scrollbar-radius, var(--radius-md));
    background-color: var(--scroll-area-scrollbar-bg, transparent);
    opacity: var(--scroll-area-scrollbar-hidden-opacity, 0);
    pointer-events: none;
    user-select: none;
    touch-action: none;
    transition: opacity var(--scroll-area-transition, var(--transition-default));

    &::before {
      content: '';
      position: absolute;
    }

    &[data-orientation='vertical'] {
      top: 0;
      inset-inline-end: 0;
      bottom: var(--scroll-area-corner-height, 0px);
      width: var(--scroll-area-scrollbar-size, 0.375rem);
      margin-block: var(--_scroll-area-scrollbar-margin);
      margin-inline-end: var(--_scroll-area-scrollbar-margin);

      &::before {
        width: var(--_scroll-area-scrollbar-hit-area-size);
        height: 100%;
        left: 50%;
        transform: translateX(-50%);
      }
    }

    &[data-orientation='horizontal'] {
      inset-inline-start: 0;
      inset-inline-end: var(--scroll-area-corner-width, 0px);
      bottom: 0;
      height: var(--scroll-area-scrollbar-size, 0.375rem);
      flex-direction: column;
      margin-inline: var(--_scroll-area-scrollbar-margin);
      margin-block-end: var(--_scroll-area-scrollbar-margin);

      &::before {
        width: 100%;
        height: var(--_scroll-area-scrollbar-hit-area-size);
        left: 0;
        right: 0;
        bottom: 50%;
        transform: translateY(50%);
      }
    }

    &[data-hovering],
    &[data-scrolling] {
      opacity: var(--scroll-area-scrollbar-visible-opacity, 1);
      pointer-events: auto;
    }

    &[data-scrolling] {
      transition-duration: 0ms;
    }
  }

  .thumb {
    box-sizing: border-box;
    border-radius: var(--scroll-area-thumb-radius, var(--radius-full));
    background-color: var(--scroll-area-thumb-bg, var(--color-border));

    &[data-orientation='vertical'] {
      width: var(--scroll-area-thumb-width, 100%);
      min-height: var(--scroll-area-thumb-min-size, 1.5rem);
    }

    &[data-orientation='horizontal'] {
      height: var(--scroll-area-thumb-height, 100%);
      min-width: var(--scroll-area-thumb-min-size, 1.5rem);
    }
  }

  .corner {
    box-sizing: border-box;
    background-color: var(--scroll-area-corner-bg, var(--scroll-area-scrollbar-bg, transparent));
  }
}

export {
  ScrollArea,
  ScrollAreaRoot,
  ScrollAreaViewport,
  ScrollAreaContent,
  ScrollAreaScrollbar,
  ScrollAreaThumb,
  ScrollAreaCorner,
} from './ScrollArea';
